mapper.select:
SELECT COUNT(*) FROM TBL_INOUT_SHIPMENT_INDICATION A
LEFT JOIN TBL_COM_PLANT B ON A.PLANTCD = B.PLANTCD
LEFT JOIN TBL_COM_COMPANY C ON A.COMPANYCD = C.COMPANYCD

  A.USEYN = 1
  AND A.SHIPMENTPLANDAY >= #{start_date}
  AND A.SHIPMENTPLANDAY <= #{end_date}
  AND A.PLANTCD = #{plant_cd}
  AND A.COMPANYCD = #{company_cd}
  AND (C.COMPANYNM LIKE #{search})
  AND A.ORDERNO = #{order_no}
  AND 1=1

SELECT A.SHIPMENTINDICATIONNO AS SHIPMENT_NO, B.PLANTNM, C.COMPANYNM, A.COMPANYCD, A.PLANTCD, A.SHIPMENTPLANDAY AS SHIP_PLAN_DATE, A.SHIPMENTDAY AS SHIP_DATE, A.SHIPMENTGUBUN, A.SHIPMENTSTATUS, A.ORDERNO, A.REMARK, (SELECT TOP 1 D.PARTNO FROM TBL_INOUT_SHIPMENT_INDICATION_DTL D WHERE D.SHIPMENTINDICATIONNO = A.SHIPMENTINDICATIONNO) as PARTNO, (SELECT TOP 1 G.PARTNM FROM TBL_INOUT_SHIPMENT_INDICATION_DTL D JOIN TBL_COM_GOODS G ON D.PARTNO = G.PARTNO WHERE D.SHIPMENTINDICATIONNO = A.SHIPMENTINDICATIONNO) as PARTNM, (SELECT TOP 1 G.STANDARD FROM TBL_INOUT_SHIPMENT_INDICATION_DTL D JOIN TBL_COM_GOODS G ON D.PARTNO = G.PARTNO WHERE D.SHIPMENTINDICATIONNO = A.SHIPMENTINDICATIONNO) as STANDARD, (SELECT TOP 1 G.UNIT FROM TBL_INOUT_SHIPMENT_INDICATION_DTL D JOIN TBL_COM_GOODS G ON D.PARTNO = G.PARTNO WHERE D.SHIPMENTINDICATIONNO = A.SHIPMENTINDICATIONNO) as UNIT, (SELECT SUM(D.SHIPMENTINDICATIONQTY) FROM TBL_INOUT_SHIPMENT_INDICATION_DTL D WHERE D.SHIPMENTINDICATIONNO = A.SHIPMENTINDICATIONNO) as SHIPQTY FROM TBL_INOUT_SHIPMENT_INDICATION A LEFT JOIN TBL_COM_PLANT B ON A.PLANTCD = B.PLANTCD LEFT JOIN TBL_COM_COMPANY C ON A.COMPANYCD = C.COMPANYCD
A.USEYN = 1 AND A.SHIPMENTPLANDAY >= #{start_date} AND A.SHIPMENTPLANDAY <= #{end_date} AND A.PLANTCD = #{plant_cd} AND A.COMPANYCD = #{company_cd} AND (C.COMPANYNM LIKE #{search} OR A.SHIPMENTINDICATIONNO LIKE #{search}) AND A.ORDERNO = #{order_no}
ORDER BY A.SHIPMENTINDICATIONNO DESC OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

SELECT COUNT(*) FROM TBL_INOUT_SHIPMENT A
LEFT JOIN TBL_COM_PLANT B ON A.PLANTCD = B.PLANTCD
LEFT JOIN TBL_COM_COMPANY C ON A.COMPANYCD = C.COMPANYCD

  A.USEYN = 1
  AND A.RAISECARDAY >= #{start_date}
  AND A.RAISECARDAY <= #{end_date}
  AND A.PLANTCD = #{plant_cd}
  AND A.COMPANYCD = #{company_cd}
  AND (C.COMPANYNM LIKE #{search} OR A.SHIPMENTNO LIKE #{search})

SELECT STOCKQTY 
FROM TBL_PROD_STOCK WITH (UPDLOCK, ROWLOCK)
WHERE LOTNO = #{lot_no}

mapper.update:
UPDATE TBL_PROD_STOCK 
SET STOCKQTY = STOCKQTY - #{qty}
WHERE LOTNO = #{lot_no}

mapper.select:
SELECT OD.ORDERNO, OD.PARTNO, OD.SEQ, G.PARTNM, G.STANDARD, G.UNIT,
       OD.UNIT_PRICE, OD.ADOFREQDT, OD.REQQTY AS ORDERQTY,
       ISNULL((SELECT SUM(SD.SHIPMENTINDICATIONQTY) FROM TBL_INOUT_SHIPMENT_INDICATION_DTL SD
               WHERE SD.ORDERNO = CAST(OD.ORDERNO AS VARCHAR) AND SD.PARTNO = OD.PARTNO), 0) AS PREV_SHIPQTY
FROM TBL_INOUT_ORDER_DETAIL OD
LEFT JOIN TBL_COM_GOODS G ON OD.PARTNO = G.PARTNO
LEFT JOIN TBL_INOUT_ORDERS O ON OD.ORDERNO = O.ORDERNO
WHERE O.USEYN = 1
AND O.COMPANYCD = #{company_cd}
AND O.PLANTCD = #{plant_cd}
AND OD.ADOFREQDT >= #{start_date}
AND OD.ADOFREQDT <= #{end_date}
ORDER BY OD.ORDERNO, OD.SEQ

mapper.update:
UPDATE TBL_INOUT_SHIPMENT_INDICATION
SET SHIPMENTSTATUS = 'DONE', SHIPMENTDAY = GETDATE(), EDITDTM = GETDATE(), EDITUSERID = #{EDITUSERID}
WHERE SHIPMENTINDICATIONNO = #{SHIPMENTINDICATIONNO}

UPDATE TBL_INOUT_SHIPMENT_INDICATION
SET USEYN = 0, EDITDTM = GETDATE(), EDITUSERID = #{EDITUSERID}
WHERE SHIPMENTINDICATIONNO = #{SHIPMENTINDICATIONNO}
